mapper.select:
select cc.id, ci.class_name, c.course_name, t.name as teacher_name, cc.class_id, cc.course_id, cc.teacher_id, cc.status from class_course cc left join class_info ci on cc.class_id = ci.id left join course c on cc.course_id = c.id left join teacher t on cc.teacher_id = t.id
and cc.class_id = #{classId}
and cc.course_id = #{courseId}
and cc.teacher_id = #{teacherId}
and cc.status = #{status}
order by cc.create_time desc
